const d = $('Build Prompts Per Member').first().json;
const ollamaResp = $input.first().json;

const rawReply = ollamaResp.message?.content || ollamaResp.response || '(no response)';

// Format: emoji + bold name header, then the reply
const formattedReply = `${d.member.emoji} *${d.member.name}* — ${d.member.role}\n\n${rawReply}`;

return [{ json: {
  channelId: d.channelId,
  threadTs: d.threadTs,
  member: d.member,
  formattedReply,
  delaySeconds: d.delaySeconds,
  payload: JSON.stringify({
    channel: d.channelId,
    thread_ts: d.threadTs,
    text: formattedReply,
    unfurl_links: false,
  })
}}];
